import { useEffect, useState } from "react";
import PlatformHighlights from "../components/PlatformHighlights";
import { statsApi } from "../services/api";

const About = () => {
  const [project, setProject] = useState(null);
  const [overview, setOverview] = useState(null);

  useEffect(() => {
    statsApi.project().then((res) => setProject(res.data)).catch(() => setProject(null));
    statsApi.overview().then((res) => setOverview(res.data)).catch(() => setOverview(null));
  }, []);

  const functionalityCards = (project?.functionalites || []).map((item, index) => ({
    icon: `F${index + 1}`,
    title: item.charAt(0).toUpperCase() + item.slice(1),
    description: item,
    color: ["from-blue-500 to-blue-600", "from-green-500 to-green-600", "from-orange-500 to-orange-600", "from-teal-500 to-teal-600", "from-indigo-500 to-indigo-600"][index % 5],
  }));

  return (
    <div className="space-y-6">
      <section className="rounded-3xl bg-gradient-to-br from-[#0B3954] via-[#146C8D] to-[#00B4D8] px-6 py-12 text-white shadow-xl md:px-10">
        <div className="max-w-4xl space-y-4">
          <span className="inline-flex rounded-full bg-white/15 px-4 py-1 text-sm font-medium backdrop-blur-sm border border-white/20">
            Plateforme d'analyse immobiliere
          </span>
          <h1 className="text-4xl font-black leading-tight md:text-5xl">{project?.title || "ID Immobilier"}</h1>
          <p className="max-w-3xl text-base text-white/90 md:text-xl">
            {project?.description ||
              "Une plateforme pour suivre les prix au m2, comparer les zones, les sources de donnees et l'evolution du marche immobilier togolais."}
          </p>
        </div>
      </section>

      <section className="grid gap-4 md:grid-cols-4">
        <div className="card-kpi">
          <p className="kpi-label">Zones analysees</p>
          <p className="kpi-value">{overview?.kpis?.zones || 0}</p>
        </div>
        <div className="card-kpi">
          <p className="kpi-label">Annonces exploitees</p>
          <p className="kpi-value">{overview?.kpis?.annonces || 0}</p>
        </div>
        <div className="card-kpi">
          <p className="kpi-label">Prix moyen / m2</p>
          <p className="kpi-value">{Number(overview?.kpis?.prix_moyen_m2 || 0).toLocaleString("fr-FR")} FCFA</p>
        </div>
        <div className="card-kpi">
          <p className="kpi-label">Sources comparees</p>
          <p className="kpi-value">{overview?.kpis?.sources || 0}</p>
        </div>
      </section>

      <section className="rounded-2xl bg-white p-6 shadow-lg">
        <h2 className="text-2xl font-bold text-[#0B3954]">Ce que fait la plateforme</h2>
        <p className="mt-2 text-slate-600">
          Le MVP permet de selectionner une zone, visualiser le prix moyen au m2, consulter l'indice immobilier,
          suivre les tendances dans le temps et comparer plusieurs sources ou plusieurs zones.
        </p>
      </section>

      <PlatformHighlights
        heading="Fonctionnalites principales"
        subheading="Les modules ci-dessous structurent l'experience utilisateur et les analyses metier."
        cards={functionalityCards}
        showActions={false}
      />

      <section className="grid gap-5 lg:grid-cols-2">
        <div className="rounded-2xl bg-white p-6 shadow-lg">
          <h3 className="text-xl font-bold text-[#0B3954]">Analyses metier</h3>
          <ul className="mt-4 space-y-3 text-sm text-slate-600">
            <li>Analyses par zone geographique et zone administrative.</li>
            <li>Analyses temporelles mensuelles et trimestrielles.</li>
            <li>Comparaison entre les sources de donnees et entre prix de marche et valeurs OTR.</li>
            <li>Calcul du prix moyen et median au m2 avec controle des valeurs extremes.</li>
          </ul>
        </div>
        <div className="rounded-2xl bg-white p-6 shadow-lg">
          <h3 className="text-xl font-bold text-[#0B3954]">Parcours utilisateur</h3>
          <ul className="mt-4 space-y-3 text-sm text-slate-600">
            {(project?.mvp || []).map((item) => (
              <li key={item}>{item.charAt(0).toUpperCase() + item.slice(1)}.</li>
            ))}
          </ul>
        </div>
      </section>
    </div>
  );
};

export default About;
